const q = String($json.customerQuestion || '').toLowerCase();
const shopName = $json.shopName || 'unser Shop';
const supportEmail = $json.supportEmail || 'support@example.com';
let category = 'allgemein';
let answer = '';

const hasAny = (words) => words.some(w => q.includes(w));

if (hasAny(['futter', 'trockenfutter', 'nassfutter', 'essen', 'ernaehrung', 'ernährung', 'magen', 'sensibel', 'allergie', 'getreide'])) {
  category = 'futterberatung';
  answer = `Gerne helfe ich dir bei der Futterauswahl. Bei empfindlichem Magen oder Allergien empfehlen wir meistens ein gut vertraegliches Futter mit klarer Zutatenliste. Achte besonders auf wenige Proteinquellen, getreidefreie Varianten und eine langsame Umstellung ueber 7 bis 10 Tage. Wenn dein Tier starke Beschwerden hat, frage bitte zusaetzlich einen Tierarzt. Im ${shopName} kannst du nach sensitivem Futter oder hypoallergenen Produkten schauen.`;
} else if (hasAny(['versand', 'lieferung', 'lieferzeit', 'paket', 'wann kommt'])) {
  category = 'versand';
  answer = `Die Lieferzeit betraegt normalerweise 2 bis 5 Werktage. Sobald deine Bestellung versendet wurde, bekommst du eine Versandbestaetigung mit Sendungsverfolgung. Falls du nach einigen Tagen nichts erhalten hast, schreibe bitte an ${supportEmail}.`;
} else if (hasAny(['rueckgabe', 'rückgabe', 'retoure', 'zurueck', 'zurück', 'umtausch', 'widerruf'])) {
  category = 'rueckgabe';
  answer = `Du kannst unbenutzte und originalverpackte Artikel normalerweise innerhalb der Widerrufsfrist zurueckgeben. Geoeffnetes Futter oder benutzte Hygieneartikel koennen aus Sicherheitsgruenden oft nicht zurueckgenommen werden. Bitte kontaktiere ${supportEmail}, damit wir dir die passenden Rueckgabe-Schritte schicken koennen.`;
} else if (hasAny(['welpe', 'puppy', 'kitten', 'jungtier', 'baby katze', 'baby hund'])) {
  category = 'jungtiere';
  answer = `Fuer Welpen und Kitten ist spezielles Junior-Futter wichtig, weil junge Tiere andere Naehrstoffe brauchen als erwachsene Tiere. Achte auf die Altersangabe, die Futtermenge und eine langsame Umstellung. Wenn du uns Alter, Rasse und Gewicht nennst, koennen wir dir besser helfen.`;
} else if (hasAny(['spielzeug', 'leine', 'halsband', 'bett', 'napf', 'zubehoer', 'zubehör'])) {
  category = 'zubehoer';
  answer = `Bei Zubehoer kommt es vor allem auf Groesse, Gewicht und Verhalten deines Tieres an. Fuer Hunde sind robuste Spielzeuge und passende Leinen wichtig. Fuer Katzen eignen sich Kratzmoeglichkeiten und sichere Spielzeuge. Wenn du mir sagst, fuer welches Tier du suchst, kann ich dir genauer helfen.`;
} else if (hasAny(['kontakt', 'support', 'hilfe', 'email', 'telefon', 'problem'])) {
  category = 'support';
  answer = `Du erreichst unseren Support unter ${supportEmail}. Beschreibe am besten kurz dein Anliegen und fuege bei Bestellungen deine Bestellnummer hinzu. Dann koennen wir dir schneller helfen.`;
} else {
  answer = `Danke fuer deine Frage. Ich helfe dir gerne zu Futter, Versand, Rueckgabe, Produkten und Support im ${shopName}. Kannst du deine Frage bitte etwas genauer stellen? Zum Beispiel: Geht es um Hundefutter, Katzenfutter, Versand oder Rueckgabe?`;
}

return [{
  json: {
    shopName,
    customerQuestion: $json.customerQuestion,
    category,
    answer,
    nextStep: 'Diese Antwort kann direkt im Website-Chat angezeigt werden.'
  }
}];
